"use client";

import { Toggle as TogglePrimitive } from "@base-ui/react/toggle";
import { ToggleGroup as ToggleGroupPrimitive } from "@base-ui/react/toggle-group";

import { cx, x } from "@/lib/utils";

import { styles } from "./toggle-group.stylex";

const ToggleGroup = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof ToggleGroupPrimitive>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.group);
  return (
    <ToggleGroupPrimitive
      className={cx(p.className, className)}
      data-slot="toggle-group"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const ToggleGroupItem = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof TogglePrimitive>, "className"> & {
  className?: string;
}) => (
  <TogglePrimitive
    className={(state) =>
      cx(
        x(styles.item, state.pressed && styles.itemPressed).className,
        className
      )
    }
    data-slot="toggle-group-item"
    style={style}
    {...props}
  />
);

export { ToggleGroup, ToggleGroupItem };

import * as stylex from "@stylexjs/stylex";

import { colors, radius } from "../tokens.stylex";

export const styles = stylex.create({
  group: {
    alignItems: "center",
    backgroundColor: colors.muted,
    borderRadius: radius.md,
    display: "inline-flex",
    gap: "0.25rem",
    padding: "0.25rem",
    width: "fit-content",
  },
  item: {
    alignItems: "center",
    backgroundColor: { ":hover": colors.background, default: "transparent" },
    borderRadius: radius.sm,
    borderWidth: 0,
    color: colors.foreground,
    cursor: { ":disabled": "not-allowed", default: "pointer" },
    display: "inline-flex",
    fontSize: "0.875rem",
    fontWeight: 500,
    gap: "0.375rem",
    height: "1.75rem",
    justifyContent: "center",
    minWidth: "1.75rem",
    opacity: { ":disabled": 0.5, default: 1 },
    outline: "none",
    paddingInline: "0.625rem",
  },
  itemPressed: {
    backgroundColor: colors.background,
    boxShadow: "0 1px 2px 0 rgb(0 0 0 / 0.05)",
  },
});
